const input = $input.first().json;
if (!input.message || !input.message.text) return [];

const text = input.message.text.trim();
const senderId = input.message.from.id;

// Tu ID de telegram y el de Cholo (hay que cambiarlos cuando los sepamos)
const mi_id = 0; // Lau
const cholo_id = 0; // Cholo

const words = text.split(' ');
const command = words[0].toLowerCase();

if (!['/gasto', '/gastocholo', '/gastolau'].includes(command)) {
  return []; // Ignorar si no es uno de estos comandos
}

let quien_pago = "Lau"; // Por defecto asume que somos nosotros
let monto = 0;
let concepto = "";

// Comando genérico: asume en base a quien manda, o a la 2da palabra
if (command === '/gasto') {
  if (isNaN(words[1])) {
    // Si la 2da palabra no es numero, es nombre: "/gasto cholo 5000 pan"
    quien_pago = words[1].toLowerCase() === 'cholo' ? 'Cholo' : 'Lau';
    monto = parseFloat(words[2]);
    concepto = words.slice(3).join(' ');
  } else {
    // Es un numero: "/gasto 5000 pan"
    quien_pago = (senderId === cholo_id) ? 'Cholo' : 'Lau';
    monto = parseFloat(words[1]);
    concepto = words.slice(2).join(' ');
  }
} else if (command === '/gastocholo') {
  quien_pago = 'Cholo';
  monto = parseFloat(words[1]);
  concepto = words.slice(2).join(' ');
} else if (command === '/gastolau') {
  quien_pago = 'Lau';
  monto = parseFloat(words[1]);
  concepto = words.slice(2).join(' ');
}

// Obtenemos mes y año actual (ej: Abril-2026)
const act = new Date();
const meses = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
const mes_periodo = `${meses[act.getMonth()]}-${act.getFullYear()}`;
const fecha = act.toLocaleDateString();

return [{
  json: {
    ID: Date.now(),
    Fecha: fecha,
    Mes_Periodo: mes_periodo,
    Concepto: concepto,
    Monto_Total: monto,
    Quien_Pago: quien_pago
  }
}];
